  'Day 2 - Reducing Mental Stimulation',
  '',
  13,
  '[{"type":"intro","dayNumber":2,"dayTitle":"Reducing Mental Stimulation","goal":"Complete Day 2 with steady, consistent action.","estimatedMinutes":13},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 2 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","If sunlight is weak, increase exposure to 20–30 minutes.","Why this works","Morning sunlight resets the brain’s circadian clock, helping the body release melatonin naturally at","night.","Without this signal, the brain stays confused about when to sleep."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones and relaxes the nervous system.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Perform 10 Minutes Of Light Physical Movement.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Mobility Stretches","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats (15 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups (10 Reps × 3)","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Movement Early In The Day Builds Sleep Pressure, Which Helps The Body Feel Naturally Tired At Night.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Today follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain in the body 6–8 hours, which can silently disturb sleep."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the voice instructions.","Let your body relax naturally.","Recommended audio length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, your body temperature drops, which naturally triggers sleepiness.","This change signals the brain that nighttime has arrived."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"exercise_routine","title":"The Military Sleep Method (fast Sleep Technique)","exercises":[{"name":"Once In Bed, Do This:","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Relax Your Forehead","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Relax Jaw And Tongue","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Drop Shoulders Completely","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Slowly Breathe Out","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Then Imagine A Calm Scene:","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"You Are Lying On A Quiet Beach At Sunset.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"You Can Hear Gentle Waves And Feel A Cool Breeze.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Keep Breathing Slowly While Focusing On The Scene.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Day 2 Sleep Trick – The Cognitive Shuffle","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"If Your Mind Keeps Thinking When Trying To Sleep, Use This Technique.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"In Your Mind, Start Naming Random Neutral Objects.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"journal","prompt":"What helped you most on Day 2?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 2 is complete.","secondaryMessage":"You reinforced reducing mental stimulation today."}]'::jsonb
