},{"name":"Slowly Breathe Out","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Then Imagine A Calm Scene:","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"You Are Lying In A Quiet Meadow Under The Stars.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"The Night Air Is Cool And Peaceful.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Everything Around You Is Calm And Still.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Focus On This Scene While Breathing Slowly.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Day 7 Sleep Trick – The “dim Light Rule”","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"About 90 Minutes Before Sleep, Start Reducing Light Exposure In Your Environment.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"journal","prompt":"What helped you most on Day 7?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 7 is complete.","secondaryMessage":"You reinforced strengthening natural melatonin today."}]'::jsonb
