  '[{"type":"intro","dayNumber":8,"dayTitle":"Strengthening Sleep Pressure","goal":"Complete Day 8 with steady, consistent action.","estimatedMinutes":16},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 8 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","If possible, combine sunlight exposure with walking for 10 minutes.","Why this works","Morning sunlight resets the brain’s circadian rhythm, helping your body release melatonin naturally","at night."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This helps lower stress hormones and prepares the body for the day.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Increased Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Starting Today, Increase Movement To 15–20 Minutes.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Exercise Routine","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"15 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Arm Circles","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20 Seconds × 3 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Forward Bends Stretch","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Slow Repetitions","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours and disturb sleep quality."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, your body temperature drops slightly, which signals the brain that it is time for","sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"breathing_exercise","title":"The Military Sleep Method (fast Sleep Technique)","instructions":"Once in bed, do this: Relax your forehead Relax jaw and tongue Drop shoulders completely Slowly breathe out Then imagine a calm scene: You are lying in a quiet forest clearing at night. A gentle breeze moves through the trees. The air is calm and peaceful. Focus on the scene while breathing slowly. Day 8 Sleep Trick – The “4-7-8 Sleep Breathing” This breathing technique helps slow the nervous system and induce sleep. Inhale through your nose for 4 seconds Hold your breath for 7 seconds Slowly exhale through your mouth for 8 seconds Repeat 4–6 cycles. Why this works This breathing pattern: slows the heart rate relaxes the nervous system signals the brain to shift into sleep mode Many people feel noticeably calmer within a few minutes. Day 8 Goal Increase sleep pressure through more physical movement while strengthening relaxation techniques before bed. By this stage many people begin noticing: stronger sleepiness at night deeper sleep cycles more consistent sleep timing","pattern":{"inhaleSeconds":4,"holdSeconds":7,"exhaleSeconds":6},"cycles":6},{"type":"journal","prompt":"What helped you most on Day 8?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 8 is complete.","secondaryMessage":"You reinforced strengthening sleep pressure today."}]'::jsonb
)
