VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  9,
  'Deepening Sleep Pressure',
  'Day 9 - Deepening Sleep Pressure',
  '',
  17,
  '[{"type":"intro","dayNumber":9,"dayTitle":"Deepening Sleep Pressure","goal":"Complete Day 9 with steady, consistent action.","estimatedMinutes":17},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 9 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Combine sunlight exposure with light walking for at least 10 minutes.","Why this works","Morning sunlight resets the brain’s circadian rhythm, helping regulate the timing of melatonin","release at night."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones and prepares the nervous system for the day.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Increased Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Increase Movement To About 20 Minutes.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Exercise Routine","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10–12 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"15 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"12 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Jumping Jacks","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20 Reps × 3 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Standing Forward Stretch","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Slow Repetitions","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can stay in the body 6–8 hours, interfering with sleep cycles."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, the body temperature naturally drops, signaling the brain that it is time for sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet mountain cabin at night.","Outside, gentle wind moves through the trees.","Inside, everything feels warm and peaceful.","Focus on the calm scene while breathing slowly.","Day 9 Sleep Trick – The “Progressive Muscle Relaxation”","This technique helps release hidden tension stored in the body, which often prevents deep sleep.","While lying in bed:","Tighten your feet muscles for 5 seconds.","Release completely for 10 seconds.","Then repeat the same pattern with:","calves","thighs","stomach","arms","shoulders","face","Tighten each muscle group briefly, then release completely.","Why this works","Many people carry physical tension without realizing it.","Releasing this tension signals the brain that the body is safe and ready for sleep.","Day 9 Goal","Strengthen physical relaxation and sleep pressure, helping the body enter deeper sleep stages.","By Day 9 many people begin noticing:","falling asleep faster","fewer night awakenings","deeper relaxation before sleep"],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 9?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 9 is complete.","secondaryMessage":"You reinforced deepening sleep pressure today."}]'::jsonb
)
