VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  11,
  'Stabilizing Deep Sleep',
  'Day 11 - Stabilizing Deep Sleep',
  '',
  18,
  '[{"type":"intro","dayNumber":11,"dayTitle":"Stabilizing Deep Sleep","goal":"Complete Day 11 with steady, consistent action.","estimatedMinutes":18},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 11 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Combine sunlight exposure with 10 minutes of walking to strengthen your circadian rhythm.","Why this works","Morning sunlight resets the brain’s internal clock, helping regulate the timing of melatonin release","at night."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and calms the nervous system.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Increased Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Total Movement Time: 25 Minutes","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Exercise Routine","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"15 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"15 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Jumping Jacks","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"30 Reps × 3 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Standing Forward Stretch","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Slow Repetitions","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, affecting sleep cycles."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, the body temperature naturally drops, signaling the brain to prepare for sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying in a quiet countryside field at night.","The stars are bright above you and the air is peaceful.","Focus on the calm scene while breathing slowly.","Day 11 Sleep Trick – The “Leg Elevation Trick”","This trick helps people who wake up too early in the morning or feel restless in bed.","Before sleeping:","Lie on your bed.","Place your legs slightly elevated on a pillow.","Keep them elevated for 5–10 minutes.","Then return to your normal sleeping position.","Why this works","Elevating the legs improves blood circulation and relaxation, which helps the body settle into deeper","sleep.","It also reduces physical restlessness that can disturb sleep during the night.","Day 11 Goal","Improve sleep stability and circulation, helping the body stay asleep longer and enter deeper sleep","cycles.","By Day 11 many people notice:","fewer early morning awakenings","deeper relaxation at night","more stable sleep patterns"],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 11?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 11 is complete.","secondaryMessage":"You reinforced stabilizing deep sleep today."}]'::jsonb
)
