VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  14,
  'Locking in the Sleep Rhythm',
  'Day 14 - Locking in the Sleep Rhythm',
  '',
  22,
  '[{"type":"intro","dayNumber":14,"dayTitle":"Locking in the Sleep Rhythm","goal":"Complete Day 14 with steady, consistent action.","estimatedMinutes":22},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 14 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Try to get sunlight before checking your phone. This strengthens the signal to your body clock.","Why this works","Morning sunlight resets the brain’s circadian rhythm, helping regulate melatonin release at night."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones and prepares the body for the day.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Increased Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Total Movement Time: 30 Minutes","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Exercise Routine","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"18–20 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20 Reps × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"15 Reps × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Jumping Jacks","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"40 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Standing Forward Stretch","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"12 Slow Repetitions","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, disturbing sleep cycles."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow the body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, the body temperature drops slightly, signaling the brain that it is time for sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying on a quiet beach at night.","You hear gentle waves and feel a cool breeze.","The night feels calm and peaceful.","Focus on the calm scene while breathing slowly.","Day 14 Sleep Trick – The “Digital Sunset Rule”","Screens are one of the biggest sleep disruptors.","Create a digital sunset 90 minutes before bedtime.","This means:","stop using phones","avoid social media","avoid bright laptop screens","avoid intense TV content","Instead, use this time for:","reading","stretching","listening to calm audio","preparing for sleep","Why this works","Screens emit blue light, which blocks melatonin production.","Reducing screen exposure before sleep allows the brain to naturally prepare for sleep.","Day 14 Goal","Lock in a stable sleep rhythm and protect the brain from late-night stimulation.","By the end of Week 2 many people notice:","feeling sleepy earlier at night","deeper sleep cycles","more consistent sleep timing","Day 2 – Building Early Sleep Pressure"],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"exercise_routine","title":"Morning Sunlight Exposure (10–20 Minutes)","exercises":[{"name":"Within 30 Minutes Of Waking, Go Outside And Expose Your Eyes To Natural Daylight.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Step Outside Your Home, Balcony, Or Street.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Do Not Wear Sunglasses.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Face The Direction Of The Sky (not Directly At The Sun).","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Stay Outside For 10–20 Minutes.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"If Possible, Walk Slowly While Getting Sunlight.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Why This Works","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Morning Sunlight Resets The Brain’s Circadian Clock, Helping Regulate Melatonin Release At Night.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This lowers stress hormones and helps the nervous system relax.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Increased Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Total Movement Time: 15 Minutes","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Exercise Routine","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"8–10 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"15 Reps × 3 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"10 Reps × 3 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Arm Circles","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20 Seconds × 3 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Standing Forward Stretch","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"8 Slow Repetitions","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":3,"title":"Caffeine Control Rule","instructions":["Today follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can remain active in the body 6–8 hours, which can disturb sleep."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended audio length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, your body temperature drops slightly, which signals the brain that it is time for","sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"exercise_routine","title":"The Military Sleep Method (fast Sleep Technique)","exercises":[{"name":"Once In Bed, Do This:","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Relax Your Forehead","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Relax Jaw And Tongue","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Drop Shoulders Completely","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Slowly Breathe Out","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Then Imagine A Calm Scene:","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"You Are Lying In A Quiet Field Under A Clear Night Sky.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"The Air Is Calm And Peaceful.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Focus On The Scene While Breathing Slowly.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Day 2 Sleep Trick – The “cognitive Shuffle”","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"If Your Mind Keeps Thinking When Trying To Sleep, Use This Technique.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"In Your Mind, Start Naming Random Neutral Objects.","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"journal","prompt":"What helped you most on Day 14?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 14 is complete.","secondaryMessage":"You reinforced locking in the sleep rhythm today."}]'::jsonb
)
