INSERT INTO public.program_days (program_id, program_slug, day_number, day_title, title, content_text, estimated_minutes, cards)
VALUES (
  (SELECT id FROM public.programs WHERE slug = 'sleep_disorder_reset' LIMIT 1),
  'sleep_disorder_reset',
  16,
  'Deep Sleep Conditioning',
  'Day 16 - Deep Sleep Conditioning',
  '',
  20,
  '[{"type":"intro","dayNumber":16,"dayTitle":"Deep Sleep Conditioning","goal":"Complete Day 16 with steady, consistent action.","estimatedMinutes":20},{"type":"lesson","title":"Today''s Focus","paragraphs":["Complete Day 16 with steady, consistent action."],"highlight":"Consistency compounds into long-term change."},{"type":"action_step","stepNumber":1,"title":"Morning Sunlight Exposure (10–20 Minutes)","instructions":["Within 30 minutes of waking, go outside and expose your eyes to natural daylight.","Step outside your home, balcony, or street.","Do not wear sunglasses.","Face the direction of the sky (not directly at the sun).","Stay outside for 10–20 minutes.","Combine sunlight exposure with light walking for the first 10 minutes.","Why this works","Morning sunlight resets the brain’s circadian rhythm, which controls the timing of melatonin release","at night."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"breathing_exercise","title":"Hydration + Nervous System Activation","instructions":"Immediately after sunlight, drink 500–700 ml of water. Then perform this breathing exercise. 10 Cycles of Physiological Sigh Inhale through nose Take a second short inhale Slowly exhale through mouth Repeat 10 times. This reduces stress hormones and calms the nervous system.","pattern":{"inhaleSeconds":4,"exhaleSeconds":6},"cycles":10},{"type":"exercise_routine","title":"Increased Morning Movement (sleep Pressure Builder)","exercises":[{"name":"Total Movement Time: 40 Minutes","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Exercise Routine","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Brisk Walking","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20–22 Minutes Continuous Walking.","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Bodyweight Squats","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"25 Reps × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Pushups","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"20 Reps × 5 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Jumping Jacks","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"50 Reps × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"Plank Hold","instructions":["Perform with steady breathing and controlled pacing."]},{"name":"40 Seconds × 4 Sets","instructions":["Perform with steady breathing and controlled pacing."]}]},{"type":"action_step","stepNumber":2,"title":"Caffeine Control Rule","instructions":["Follow this rule strictly:","No caffeine after 2 PM","This includes:","coffee","tea","energy drinks","pre-workout drinks","Caffeine can stay active in the body 6–8 hours, disturbing sleep cycles."],"whyThisWorks":"Small consistent actions reinforce stability and reduce automatic, stress-driven reactions."},{"type":"mindfulness_exercise","title":"Evening Nervous System Downshift","steps":["About 60 minutes before bed, listen to your guided sleep meditation audio.","Lie comfortably in bed.","Play the meditation audio at low volume.","Close your eyes and follow the instructions.","Allow your body to relax naturally.","Recommended length: 10–20 minutes."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"Body Temperature Sleep Trick","steps":["Take a warm shower 60–90 minutes before sleep.","Why this works","After the shower, the body temperature naturally drops, signaling the brain that it is time to sleep."],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"mindfulness_exercise","title":"The Military Sleep Method (fast Sleep Technique)","steps":["Once in bed, do this:","Relax your forehead","Relax jaw and tongue","Drop shoulders completely","Slowly breathe out","Then imagine a calm scene:","You are lying beside a quiet river under a peaceful night sky.","The sound of water is gentle and relaxing.","Focus on the calm scene while breathing slowly.","Day 16 Sleep Trick – The “Cognitive Defusion Trick”","Sometimes thoughts keep repeating in the mind at night.","Instead of fighting the thought, label it and let it pass.","When a thought appears, say silently:","“This is just a thought.”","Then let it pass and return to slow breathing.","Do not analyze or continue the thought.","Why this works","Trying to stop thoughts often makes them stronger.","Labeling them as just thoughts removes their emotional power and allows the brain to relax.","Day 16 Goal","Train the brain to disconnect from mental stimulation, allowing the body to transition into sleep","more smoothly.","By Day 16 many people notice:","fewer racing thoughts","faster sleep onset","deeper relaxation before sleep"],"completionMessage":"Stay with the practice until your body and mind feel steadier."},{"type":"journal","prompt":"What helped you most on Day 16?","helperText":"Write one or two practical observations.","followUpPrompt":"What will you repeat tomorrow?"},{"type":"close","message":"Day 16 is complete.","secondaryMessage":"You reinforced deep sleep conditioning today."}]'::jsonb
)
